            if output.data_quality_blocked {
                "是"
            } else {
                "否"
            }
        ),
        format!("动作：{}", output.action),
        String::new(),
        "## key evidence".to_string(),
    ];

    push_list(&mut lines, &output.key_evidence, "暂无关键指标证据。");
    lines.push(String::new());
    lines.push("## failed sources".to_string());
